#include<cstdio>
#include<vector>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define Rep(a,i) for(int i=0;i<(a);++i)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
unsigned seed=998244353;inline int Rand(){seed^=seed<<17;seed^=seed>>13;seed^=seed<<5;return seed>>20;}
int n,d,K;
struct Mat
{
	std::vector< std::vector<int> > a; int n,m;
	inline Mat(int x=0,int y=0){n=x;m=y;a.resize(n);Rep(n,i)a[i].resize(m);}
	inline std::vector<int>& operator [] (const int &x){return a[x];}
	inline bool operator == (Mat b)const
		{if(n!=b.n||m!=b.m)return false;Rep(n,i)Rep(m,j)if(a[i][j]!=b[i][j])return false;return true;}
	inline bool friend operator != (Mat x,Mat y){return !(x==y);}
	inline Mat friend operator * (Mat a, Mat b)
	{
		Mat c(a.n,b.m);
		if(K==2)Rep(a.n,i)Rep(b.m,j){Rep(b.n,k)c[i][j]+=a[i][k]*b[k][j];c[i][j]&=1;}
		else Rep(a.n,i)Rep(b.m,j){Rep(b.n,k)c[i][j]+=a[i][k]*b[k][j];c[i][j]%=3;};
		return c;
	}
};

namespace Sub2
{
	inline void mian(Mat &A)
	{
		Mat AT(d,n);Rep(n,i)Rep(d,j)AT[j][i]=A[i][j]&=1;Mat R(n,1);
		int TT=5;while(TT--)
		{
			int sum=0;Rep(n,i)sum+=R[i][0]=Rand()&1;sum&=1;
			Mat BR=A*(AT*R);Rep(n,i)if(BR[i][0]!=sum)Rep(n,j)if(i!=j)
			{
				bool s=0;Rep(d,k)s^=(A[i][k]&A[j][k]);
				if(!s){printf("%d %d\n",min(i,j)+1,max(i,j)+1);return;}
			}
		}
		puts("-1 -1");return;
	}
}
namespace Sub3
{
	inline void mian(Mat &A)
	{
		Mat AT(d,n);Rep(n,i)Rep(d,j)AT[j][i]=A[i][j]%=3;
		int TT=5;while(TT--)
		{
			int sum=0;Mat R=A;Rep(n,i)
			{
				int x=Rand()%3;sum+=x;
				Rep(d,j)(R[i][j]*=x)%=3;
			}
			R=AT*R;sum%=3;Rep(n,i)
			{
				int ss=0;Rep(d,j)Rep(d,k)ss+=A[i][j]*R[j][k]*AT[k][i];
				if(ss%3!=sum)
				{
					Rep(n,j)if(i!=j)
					{
						int s=0;Rep(d,k)s+=A[i][k]*A[j][k];
						if(!(s%3)){printf("%d %d\n",min(i,j)+1,max(i,j)+1);return;}
					}
				}
			}
		}
		puts("-1 -1");return;
	}
}
int main()
{
//	int T=100;while(T--)printf("%u\n",Rand());
	n=read();d=read();K=read();
	Mat A(n,d);Rep(n,i)Rep(d,j)A[i][j]=read();
	K==2?Sub2::mian(A):Sub3::mian(A);return 0;
}
